// -------- Module Bundler for Node.js SEA --------
// Resolves local require() calls and inlines into a single file
// Uses only Node.js stdlib — no third-party dependencies
const fs = require('node:fs');
const path = require('node:path');

// -------- Configuration --------
const ROOT = path.resolve(__dirname, '..');
const ENTRY = path.join(ROOT, 'src', 'main.js');
const OUTPUT = path.join(ROOT, 'dist', 'bundle.js');

const moduleMap = new Map();
const moduleOrder = [];

// -------- Module Resolution --------

// -- Resolve a relative require path to an absolute file path --
function resolveModule(fromFile, reqPath) {
  const dir = path.dirname(fromFile);
  const candidates = [
    path.resolve(dir, reqPath),
    path.resolve(dir, reqPath + '.js'),
    path.resolve(dir, reqPath, 'index.js'),
  ];

  for (const c of candidates) {
    if (fs.existsSync(c) && fs.statSync(c).isFile()) return c;
  }

  throw new Error(`Cannot resolve "${reqPath}" from ${fromFile}`);
}

// -------- Dependency Walking --------

// -- Recursively process a module and all its local dependencies --
function processModule(filePath) {
  const absPath = path.resolve(filePath);
  if (moduleMap.has(absPath)) return;

  const content = fs.readFileSync(absPath, 'utf-8');
  const deps = [];

  // -- Only resolve local requires (starting with . or ..) --
  const pattern = /require\(['"](\.[^'"]+)['"]\)/g;
  let match;

  while ((match = pattern.exec(content)) !== null) {
    const resolved = resolveModule(absPath, match[1]);
    deps.push({ original: match[0], resolved });
    processModule(resolved);
  }

  moduleMap.set(absPath, { content, deps });
  moduleOrder.push(absPath);
}

// -------- Bundle Generation --------

function bundle() {
  processModule(ENTRY);

  // -- Use relative paths as module IDs for cleaner output --
  const toId = (abs) => path.relative(ROOT, abs);

  const lines = [
    '// SonarQube Findings Enricher — Bundled for SEA',
    '// Generated by build/bundle.js — do not edit manually',
    '',
    'const __modules = {};',
    'const __cache = {};',
    '',
    'function __require(id) {',
    '  if (__cache[id]) return __cache[id].exports;',
    '  const mod = { exports: {} };',
    '  __cache[id] = mod;',
    '  __modules[id](mod, mod.exports, __require);',
    '  return mod.exports;',
    '}',
    '',
  ];

  for (const absPath of moduleOrder) {
    const { content, deps } = moduleMap.get(absPath);
    const id = toId(absPath);
    let patched = content;

    // -- Replace local requires with __require using module IDs --
    for (const dep of deps) {
      const depId = toId(dep.resolved);
      patched = patched.split(dep.original).join(`__require("${depId}")`);
    }

    lines.push(
      `__modules["${id}"] = function(module, exports, __require) {`,
      patched,
      '};',
      ''
    );
  }

  // -- Execute entry point --
  lines.push(`__require("${toId(path.resolve(ENTRY))}");`);

  // -- Write output --
  const distDir = path.dirname(OUTPUT);
  if (!fs.existsSync(distDir)) fs.mkdirSync(distDir, { recursive: true });
  fs.writeFileSync(OUTPUT, lines.join('\n'), 'utf-8');

  console.log(`Bundled ${moduleOrder.length} modules -> ${OUTPUT}`);
}

bundle();
